import { defineComponentSlotStyle } from "@yamada-ui/react"
import { nativeAccordionStyle } from "../native-accordion"

export const accordionStyle = defineComponentSlotStyle({
  base: {
    ...nativeAccordionStyle.base,
    button: {
      ...nativeAccordionStyle.base?.button,
      "&[aria-disabled=true]": { cursor: "default" },
    },
    icon: {
      ...nativeAccordionStyle.base?.icon,
      _expanded: { transform: "rotate(180deg)" },
    },
    panel: { ...nativeAccordionStyle.base?.panel, pb: "3" },
  },

  variants: nativeAccordionStyle.variants,

  defaultProps: {
    variant: "plain",
  },
})

export type AccordionStyle = typeof accordionStyle

import type { CSSProperties } from "react"
import { a11y, page, render, renderHook } from "#test/browser"
import { noop } from "@yamada-ui/react"
import { BoxIcon } from "../icon"
import { Accordion } from "./"
import { useAccordion, useAccordionItem } from "./use-accordion"

const items = [
  {
    button: "Accordion Label 1",
    children: "This is an accordion item 1",
  },
  {
    button: "Accordion Label 2",
    children: "This is an accordion item 2",
  },
  {
    button: "Accordion Label 3",
    children: "This is an accordion item 3",
  },
]

interface ItemPropsMergeProbeProps {
  argsClassName: string
  argsId: string
  argsStyle: CSSProperties
  restClassName: string
  restId: string
  restStyle: CSSProperties
  argsOnClick: () => void
  argsRef: (node: HTMLDivElement | null) => void
  restOnClick: () => void
  restRef: (node: HTMLDivElement | null) => void
}

const ItemPropsMergeProbe = ({
  argsClassName,
  argsId,
  argsOnClick,
  argsRef,
  argsStyle,
  restClassName,
  restId,
  restOnClick,
  restRef,
  restStyle,
}: ItemPropsMergeProbeProps) => {
  const { getItemProps } = useAccordionItem({
    id: restId,
    ref: restRef,
    className: restClassName,
    style: restStyle,
    index: 0,
    onClick: restOnClick,
  })

  return (
    <div
      {...getItemProps({
        id: argsId,
        ref: argsRef,
        className: argsClassName,
        style: argsStyle,
        "data-testid": "item-probe",
        onClick: argsOnClick,
      })}
    />
  )
}

describe("<Accordion />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Accordion.Root>
        <Accordion.Item button="Accordion Label" index={0}>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(Accordion.Root.displayName).toBe("AccordionRoot")
    expect(Accordion.Item.displayName).toBe("AccordionItem")
    expect(Accordion.Button.displayName).toBe("AccordionButton")
    expect(Accordion.Panel.displayName).toBe("AccordionPanel")
  })

  test("sets `className` correctly", async () => {
    await render(
      <Accordion.Root data-testid="root">
        <Accordion.Item data-testid="item" button="Accordion Label" index={0}>
          <Accordion.Panel data-testid="panel">
            This is an accordion item
          </Accordion.Panel>
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByTestId("root"))
      .toHaveClass("ui-accordion__root")
    await expect
      .element(page.getByTestId("item"))
      .toHaveClass("ui-accordion__item")
    await expect
      .element(page.getByTestId("panel"))
      .toHaveClass("ui-accordion__panel")
    await expect
      .element(page.getByRole("button", { name: /Accordion Label/i }))
      .toHaveClass("ui-accordion__button")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Accordion.Root data-testid="root">
        <Accordion.Item data-testid="item" button="Accordion Label" index={0}>
          <Accordion.Panel data-testid="panel">
            This is an accordion item
          </Accordion.Panel>
        </Accordion.Item>
      </Accordion.Root>,
    )

    expect(page.getByTestId("root").element().tagName).toBe("DIV")

    const item = page.getByTestId("item").element()
    expect(item.tagName).toBe("DIV")
    expect(item.children[0]?.tagName).toBe("H3")

    expect(page.getByTestId("panel").element().tagName).toBe("DIV")
    expect(
      page.getByRole("button", { name: /Accordion Label/i }).element().tagName,
    ).toBe("BUTTON")
  })

  test("should render correctly with defaultIndex item expanded", async () => {
    await render(<Accordion.Root defaultIndex={0} items={items} />)

    const button = page.getByRole("button", {
      name: /Accordion Label 1/i,
    })
    await expect.element(button).toHaveAttribute("aria-expanded", "true")
    await expect
      .element(page.getByText("This is an accordion item 1"))
      .toBeVisible()
  })

  test("should work correctly with toggle", async () => {
    const { user } = await render(<Accordion.Root items={items} toggle />)

    const button = page.getByRole("button", { name: /Accordion Label 1/i })

    await user.click(button)
    await expect.element(button).toHaveAttribute("aria-expanded", "true")

    await user.click(button)
    await expect.element(button).toHaveAttribute("aria-expanded", "false")
  })

  test("should show multiple items", async () => {
    const { user } = await render(
      <Accordion.Root defaultIndex={[0, 1]} items={items} multiple />,
    )

    const item1 = page.getByRole("button", { name: /Accordion Label 1/i })
    const item2 = page.getByRole("button", { name: /Accordion Label 2/i })
    const item3 = page.getByRole("button", { name: /Accordion Label 3/i })

    await expect.element(item1).toHaveAttribute("aria-expanded", "true")
    await expect.element(item2).toHaveAttribute("aria-expanded", "true")
    await expect.element(item3).toHaveAttribute("aria-expanded", "false")

    await user.click(item3)
    await expect.element(item3).toHaveAttribute("aria-expanded", "true")
  })

  test("should render a disabled item", async () => {
    await render(
      <Accordion.Root>
        <Accordion.Item button="Accordion Label" disabled index={0}>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    const button = page.getByRole("button", { name: /Accordion Label/i })
    await expect.element(button).toBeDisabled()
  })

  test("should render item with panel", async () => {
    await render(
      <Accordion.Root defaultIndex={0}>
        <Accordion.Item button="Accordion Label" index={0}>
          <Accordion.Panel>This is an accordion item</Accordion.Panel>
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByText("This is an accordion item"))
      .toBeVisible()
  })

  test("should render item with custom icon", async () => {
    const { user } = await render(
      <Accordion.Root
        icon={({ expanded }) => (
          <BoxIcon
            data-icon={!expanded ? "plus" : "minus"}
            data-testid="custom-icon"
          />
        )}
      >
        <Accordion.Item button="Accordion Label" index={0}>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "plus")

    await user.click(page.getByRole("button", { name: /Accordion Label/i }))

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "minus")
  })

  test("should render item with custom icon in AccordionItem", async () => {
    const { user } = await render(
      <Accordion.Root>
        <Accordion.Item
          button="Accordion Label"
          icon={({ expanded }) => (
            <BoxIcon
              data-icon={!expanded ? "plus" : "minus"}
              data-testid="custom-icon"
            />
          )}
          index={0}
        >
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "plus")

    await user.click(page.getByRole("button", { name: /Accordion Label/i }))

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "minus")
  })

  test("should render item with custom icon in AccordionButton", async () => {
    const { user } = await render(
      <Accordion.Root>
        <Accordion.Item index={0}>
          <Accordion.Button
            icon={({ expanded }) => (
              <BoxIcon
                data-icon={!expanded ? "plus" : "minus"}
                data-testid="custom-icon"
              />
            )}
          >
            Accordion Label
          </Accordion.Button>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "plus")

    await user.click(page.getByRole("button", { name: /Accordion Label/i }))

    await expect
      .element(page.getByTestId("custom-icon"))
      .toHaveAttribute("data-icon", "minus")
  })

  test("should render item with custom label", async () => {
    await render(
      <Accordion.Root>
        <Accordion.Item index={0}>
          <Accordion.Button>Accordion Label</Accordion.Button>
          <Accordion.Panel>This is an accordion item</Accordion.Panel>
        </Accordion.Item>
      </Accordion.Root>,
    )

    await expect
      .element(page.getByRole("button", { name: /Accordion Label/i }))
      .toBeVisible()
  })

  test("should render label with function label", async () => {
    const { user } = await render(
      <Accordion.Root>
        <Accordion.Item
          button={({ disabled, expanded }) => {
            if (disabled) return <p>Is disabled</p>

            if (expanded) return <p>Is expanded</p>
            else return <p>Not expanded</p>
          }}
          index={0}
        >
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    const button = page.getByRole("button", { name: /Not expanded/i })
    await expect.element(button).toBeVisible()

    await user.click(button)

    await expect
      .element(page.getByRole("button", { name: /Is expanded/i }))
      .toBeVisible()
  })

  test("focus moves correctly on ArrowDown", async () => {
    const { user } = await render(<Accordion.Root items={items} />)

    const item1 = page.getByRole("button", { name: /Accordion Label 1/i })
    const item2 = page.getByRole("button", { name: /Accordion Label 2/i })
    const item3 = page.getByRole("button", { name: /Accordion Label 3/i })

    await user.click(item1)
    await expect.element(item1).toHaveFocus()

    await user.keyboard("{ArrowDown>}")
    await expect.element(item2).toHaveFocus()

    await user.keyboard("{ArrowDown>}")
    await expect.element(item3).toHaveFocus()

    await user.keyboard("{ArrowDown>}")
    await expect.element(item1).toHaveFocus()
  })

  test("focus moves correctly on ArrowUp", async () => {
    const { user } = await render(<Accordion.Root items={items} />)

    const item1 = page.getByRole("button", { name: /Accordion Label 1/i })
    const item2 = page.getByRole("button", { name: /Accordion Label 2/i })
    const item3 = page.getByRole("button", { name: /Accordion Label 3/i })

    await user.click(item1)
    await expect.element(item1).toHaveFocus()

    await user.keyboard("{ArrowUp>}")
    await expect.element(item3).toHaveFocus()

    await user.keyboard("{ArrowUp>}")
    await expect.element(item2).toHaveFocus()
  })

  test("focus moves correctly on Home", async () => {
    const { user } = await render(<Accordion.Root items={items} />)

    const item1 = page.getByRole("button", { name: /Accordion Label 1/i })
    const item3 = page.getByRole("button", { name: /Accordion Label 3/i })

    await user.click(item3)
    await expect.element(item3).toHaveFocus()

    await user.keyboard("{Home>}")
    await expect.element(item1).toHaveFocus()
  })

  test("focus moves correctly on End", async () => {
    const { user } = await render(<Accordion.Root items={items} />)

    const item1 = page.getByRole("button", { name: /Accordion Label 1/i })
    const item3 = page.getByRole("button", { name: /Accordion Label 3/i })

    await user.click(item1)
    await expect.element(item1).toHaveFocus()

    await user.keyboard("{End>}")
    await expect.element(item3).toHaveFocus()
  })

  test("correct warnings should be issued when multiple and toggle", async () => {
    const consoleWarnSpy = vi.spyOn(console, "warn").mockImplementation(noop)

    await render(
      <Accordion.Root multiple toggle>
        <Accordion.Item button="Accordion Label" index={0}>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    await vi.waitFor(() =>
      expect(consoleWarnSpy).toHaveBeenLastCalledWith(
        "Accordion: If 'multiple' is passed, 'toggle' will be ignored. Either remove 'toggle' or 'multiple' depending on whether you want multiple accordions visible or not",
      ),
    )

    consoleWarnSpy.mockRestore()
  })

  test("correct warnings should be issued when multiple and defaultIndex is not array", async () => {
    const consoleWarnSpy = vi.spyOn(console, "warn").mockImplementation(noop)

    await render(
      <Accordion.Root defaultIndex={1} multiple>
        <Accordion.Item button="Accordion Label" index={0}>
          This is an accordion item
        </Accordion.Item>
      </Accordion.Root>,
    )

    await vi.waitFor(() =>
      expect(consoleWarnSpy).toHaveBeenLastCalledWith(
        "Accordion: If 'multiple' is passed, then 'index' or 'defaultIndex' must be an array.",
      ),
    )

    consoleWarnSpy.mockRestore()
  })

  test("merges props correctly in `getRootProps`", async () => {
    const restOnClick = vi.fn()
    const argsOnClick = vi.fn()
    const restRef = vi.fn()
    const argsRef = vi.fn()
    const { result } = await renderHook(() =>
      useAccordion({
        id: "rest-id",
        ref: restRef,
        className: "rest-class",
        style: { color: "red" },
        onClick: restOnClick,
      }),
    )

    const rootProps = result.current.getRootProps({
      id: "args-id",
      ref: argsRef,
      className: "args-class",
      style: { backgroundColor: "blue" },
      onClick: argsOnClick,
    })

    expect(rootProps.className).toContain("rest-class")
    expect(rootProps.className).toContain("args-class")
    expect(rootProps.style).toMatchObject({
      backgroundColor: "blue",
      color: "red",
    })
    expect(rootProps.id).toBe("args-id")

    rootProps.onClick?.(new MouseEvent("click") as any)
    expect(restOnClick).toHaveBeenCalledTimes(1)
    expect(argsOnClick).toHaveBeenCalledTimes(1)

    expect(typeof rootProps.ref).toBe("function")

    const node = document.createElement("div")
    ;(rootProps.ref as (node: HTMLDivElement | null) => void)(node)

    expect(restRef).toHaveBeenCalledWith(node)
    expect(argsRef).toHaveBeenCalledWith(node)
  })

  test("merges props correctly in `getItemProps`", async () => {
    const restOnClick = vi.fn()
    const argsOnClick = vi.fn()
    const restRef = vi.fn()
    const argsRef = vi.fn()
    await render(
      <Accordion.Root>
        <ItemPropsMergeProbe
          argsClassName="args-class"
          argsId="args-id"
          argsOnClick={argsOnClick}
          argsRef={argsRef}
          argsStyle={{ backgroundColor: "blue" }}
          restClassName="rest-class"
          restId="rest-id"
          restOnClick={restOnClick}
          restRef={restRef}
          restStyle={{ color: "red" }}
        />
      </Accordion.Root>,
    )

    const item = page.getByTestId("item-probe")
    const itemEl = item.element()

    await expect.element(item).toHaveClass("rest-class")
    await expect.element(item).toHaveClass("args-class")
    expect(itemEl.id).toBe("args-id")
    expect(itemEl).toBeInstanceOf(HTMLElement)
    const htmlItemEl = itemEl as HTMLElement
    expect(htmlItemEl.style.color).toBe("red")
    expect(htmlItemEl.style.backgroundColor).toBe("blue")

    itemEl.dispatchEvent(new MouseEvent("click", { bubbles: true }))
    expect(restOnClick).toHaveBeenCalledTimes(1)
    expect(argsOnClick).toHaveBeenCalledTimes(1)

    expect(restRef).toHaveBeenCalledWith(itemEl)
    expect(argsRef).toHaveBeenCalledWith(itemEl)
  })
})

"use client"

import type { HTMLProps, HTMLStyledProps, ThemeProps, ReactNodeOrFunction } from "@yamada-ui/react"
import type { CollapseProps } from "../collapse"
import type { WithTransitionProps } from "../motion"
import type { AccordionStyle } from "./accordion.style"
import type { UseAccordionItemProps, UseAccordionProps } from "./use-accordion"
import { Children, cloneElement, isValidElement, useMemo } from "react"
import { createSlotComponent, styled, createContext, isString, runIfFn, useSplitChildren } from "@yamada-ui/react"
import { Collapse } from "../collapse"
import { ChevronDownIcon } from "../icon"
import { accordionStyle } from "./accordion.style"
import {
  AccordionContext,
  AccordionDescendantsContext,
  AccordionItemContext,
  useAccordion,
  useAccordionItem,
  useAccordionItemContext,
} from "./use-accordion"

interface AccordionCallBackProps {
  disabled?: boolean
  expanded?: boolean
}

export interface AccordionItem extends Omit<AccordionItemProps, "index"> {}

interface ComponentContext extends Pick<
  AccordionRootProps,
  "icon" | "iconHidden"
> {}

export interface AccordionRootProps
  extends
    Omit<HTMLStyledProps, "onChange">,
    ThemeProps<AccordionStyle>,
    UseAccordionProps {
  /**
   * The accordion icon for all items to use.
   */
  icon?: ReactNodeOrFunction<AccordionCallBackProps>
  /**
   * If `true`, hide the accordion icon for all items.
   *
   * @default false
   */
  iconHidden?: boolean
  /**
   * If provided, generate elements based on items.
   */
  items?: AccordionItem[]
}

interface ItemComponentContext extends Pick<AccordionItemProps, "icon"> {}

const [ItemComponentContext, useItemComponentContext] =
  createContext<ItemComponentContext>({
    name: "ItemComponentContext",
  })

const {
  ComponentContext,
  PropsContext: AccordionPropsContext,
  useComponentContext,
  usePropsContext: useAccordionPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<AccordionRootProps, AccordionStyle, ComponentContext>(
  "accordion",
  accordionStyle,
)

export { AccordionPropsContext, useAccordionPropsContext }

/**
 * `Accordion` is a component for a list that displays information in an expandable or collapsible manner.
 *
 * @see https://yamada-ui.com/docs/components/accordion
 */
export const AccordionRoot = withProvider<"div", AccordionRootProps>(
  ({ children, icon, iconHidden, items, ...props }) => {
    const {
      descendants,
      focusedIndex,
      index,
      multiple,
      setFocusedIndex,
      setIndex,
      toggle,
      getRootProps,
    } = useAccordion(props)
    const computedChildren = useMemo(() => {
      if (children) return children

      return items?.map((props, index) => (
        <AccordionItem key={index} index={index} {...props} />
      ))
    }, [children, items])
    const context = useMemo(
      () => ({
        focusedIndex,
        index,
        multiple,
        setFocusedIndex,
        setIndex,
        toggle,
      }),
      [focusedIndex, index, multiple, setFocusedIndex, setIndex, toggle],
    )
    const componentContext = useMemo(
      () => ({ icon, iconHidden }),
      [icon, iconHidden],
    )

    return (
      <AccordionDescendantsContext value={descendants}>
        <AccordionContext value={context}>
          <ComponentContext value={componentContext}>
            <styled.div {...getRootProps()}>{computedChildren}</styled.div>
          </ComponentContext>
        </AccordionContext>
      </AccordionDescendantsContext>
    )
  },
  "root",
)()

export interface AccordionItemProps
  extends
    Omit<HTMLStyledProps, "children">,
    Omit<UseAccordionItemProps, "children"> {
  /**
   * The accordion button to use.
   */
  button?: ReactNodeOrFunction<AccordionCallBackProps>
  /**
   * The accordion children to use.
   */
  children?: ReactNodeOrFunction<AccordionCallBackProps>
  /**
   * The accordion icon to use.
   */
  icon?: ReactNodeOrFunction<AccordionCallBackProps>
}

export const AccordionItem = withContext<"div", AccordionItemProps>(
  ({ button, children, icon, ...rest }) => {
    const {
      disabled,
      open,
      getButtonProps,
      getIconProps,
      getItemProps,
      getPanelProps,
    } = useAccordionItem(rest)
    const computedChildren = useMemo(
      () => runIfFn(children, { disabled, expanded: open }),
      [children, disabled, open],
    )
    const [omittedChildren, customAccordionButton, customAccordionPanel] =
      useSplitChildren(computedChildren, AccordionButton, AccordionPanel)
    const context = useMemo(
      () => ({
        disabled,
        icon,
        open,
        getButtonProps,
        getIconProps,
        getPanelProps,
      }),
      [disabled, getButtonProps, getPanelProps, getIconProps, icon, open],
    )
    const componentContext = useMemo(() => ({ icon }), [icon])

    return (
      <AccordionItemContext value={context}>
        <ItemComponentContext value={componentContext}>
          <styled.div {...getItemProps()}>
            {customAccordionButton ?? (
              <AccordionButton>
                {runIfFn(button, { disabled, expanded: open })}
              </AccordionButton>
            )}
            {customAccordionPanel ?? (
              <AccordionPanel>{omittedChildren}</AccordionPanel>
            )}
          </styled.div>
        </ItemComponentContext>
      </AccordionItemContext>
    )
  },
  "item",
)()

export interface AccordionButtonProps extends HTMLStyledProps<"button"> {
  /**
   * The accordion icon to use.
   */
  icon?: ReactNodeOrFunction<AccordionCallBackProps>
  /**
   * Props the container element.
   */
  containerProps?: HTMLStyledProps
}

export const AccordionButton = withContext<"button", AccordionButtonProps>(
  ({ children, icon: customIcon, containerProps, ...rest }) => {
    const { icon: rootIcon } = useComponentContext()
    const { icon: itemIcon } = useItemComponentContext()
    const { disabled, open, getButtonProps } = useAccordionItemContext()
    const props = { disabled, expanded: open }

    return (
      <styled.h3 {...containerProps}>
        <styled.button {...getButtonProps(rest)}>
          {children}

          <AccordionIcon>
            {runIfFn(customIcon, props) ??
              runIfFn(itemIcon, props) ??
              runIfFn(rootIcon, props)}
          </AccordionIcon>
        </styled.button>
      </styled.h3>
    )
  },
  "button",
)()

interface AccordionIconProps extends HTMLStyledProps<"svg"> {}

export const AccordionIcon = withContext<"svg", AccordionIconProps>(
  ({ children = <ChevronDownIcon />, ...rest }) => {
    const { iconHidden } = useComponentContext()
    const { getIconProps } = useAccordionItemContext()

    if (iconHidden) return null

    if (isValidElement<HTMLProps<"svg">>(children))
      return cloneElement(
        children,
        getIconProps({
          ...rest,
          ...children.props,
        }),
      )

    return Children.count(children) > 1 ? Children.only(null) : null
  },
  "icon",
)()

export interface AccordionPanelProps
  extends
    Omit<HTMLStyledProps, "transition">,
    Pick<
      CollapseProps,
      | "animationOpacity"
      | "endingHeight"
      | "startingHeight"
      | keyof WithTransitionProps
    > {}

export const AccordionPanel = withContext<"div", AccordionPanelProps>(
  ({
    animationOpacity,
    children,
    delay,
    duration,
    endingHeight,
    startingHeight,
    transition,
    transitionEnd,
    unmountOnExit,
    ...rest
  }) => {
    const { open, getPanelProps } = useAccordionItemContext()

    return (
      <Collapse
        {...{
          animationOpacity,
          delay,
          duration,
          endingHeight,
          open,
          startingHeight,
          transition,
          transitionEnd,
          unmountOnExit,
        }}
      >
        <styled.div {...getPanelProps(rest)}>
          {isString(children) ? <styled.p>{children}</styled.p> : children}
        </styled.div>
      </Collapse>
    )
  },
  "panel",
)()

"use client"

import type { KeyboardEvent } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import { useCallback, useEffect, useId, useState } from "react"
import {
  mergeProps,
  ariaAttr,
  createContext,
  cx,
  dataAttr,
  handlerAll,
  isArray,
  mergeRefs,
  runKeyAction,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { createDescendants } from "../../hooks/use-descendants"

const {
  DescendantsContext: AccordionDescendantsContext,
  useDescendant: useAccordionDescendant,
  useDescendants: useAccordionDescendants,
} = createDescendants<HTMLButtonElement>()

export {
  AccordionDescendantsContext,
  useAccordionDescendant,
  useAccordionDescendants,
}

interface AccordionContext extends Omit<
  UseAccordionReturn,
  "descendants" | "getRootProps"
> {}

const [AccordionContext, useAccordionContext] = createContext<AccordionContext>(
  { name: "AccordionContext" },
)

export { AccordionContext, useAccordionContext }

interface AccordionItemContext extends Omit<
  UseAccordionItemReturn,
  "getItemProps"
> {}

const [AccordionItemContext, useAccordionItemContext] =
  createContext<AccordionItemContext>({
    name: "AccordionItemContext",
  })

export { AccordionItemContext, useAccordionItemContext }

export interface UseAccordionProps extends Omit<HTMLProps, "onChange"> {
  /**
   * The initial index(es) of the accordion item to expand.
   */
  defaultIndex?: number | number[]
  /**
   * The index(es) of the accordion item to expand.
   */
  index?: number | number[]
  /**
   * If `true`, multiple accordion items can be expanded at once.
   *
   * @default false
   */
  multiple?: boolean
  /**
   * If `true`, any expanded accordion item can be collapsed again.
   *
   * @default false
   */
  toggle?: boolean
  /**
   * The callback invoked when accordion items are expanded or collapsed.
   */
  onChange?: (index: number | number[]) => void
}

export const useAccordion = ({
  defaultIndex: defaultIndexProp,
  index: indexProp,
  multiple,
  toggle,
  onChange,
  ...rest
}: UseAccordionProps = {}) => {
  if (
    (indexProp || defaultIndexProp) != null &&
    !isArray(indexProp || defaultIndexProp) &&
    multiple
  ) {
    console.warn(
      `Accordion: If 'multiple' is passed, then 'index' or 'defaultIndex' must be an array.`,
    )
  }

  if (multiple && toggle) {
    console.warn(
      `Accordion: If 'multiple' is passed, 'toggle' will be ignored. Either remove 'toggle' or 'multiple' depending on whether you want multiple accordions visible or not`,
    )
  }

  const descendants = useAccordionDescendants()

  const [focusedIndex, setFocusedIndex] = useState<number>(-1)

  const [index, setIndex] = useControllableState({
    defaultValue: () =>
      multiple ? (defaultIndexProp ?? []) : (defaultIndexProp ?? -1),
    value: indexProp,
    onChange,
  })

  const getRootProps: PropGetter = useCallback(
    (props = {}) => mergeProps(rest, props)(),
    [rest],
  )

  useEffect(() => {
    return () => setFocusedIndex(-1)
  }, [])

  return {
    descendants,
    focusedIndex,
    index,
    multiple,
    setFocusedIndex,
    setIndex,
    toggle,
    getRootProps,
  }
}

export type UseAccordionReturn = ReturnType<typeof useAccordion>

export interface UseAccordionItemProps extends HTMLProps {
  /**
   * The index of the accordion item.
   */
  index: number
  /**
   * If `true`, the accordion item will be disabled.
   *
   * @default false
   */
  disabled?: boolean
}

export const useAccordionItem = ({
  disabled,
  index,
  ...rest
}: UseAccordionItemProps) => {
  const itemId = useId()
  const panelId = useId()
  const {
    index: selectedIndex,
    multiple,
    setFocusedIndex,
    setIndex,
    toggle,
  } = useAccordionContext()
  const { descendants, register } = useAccordionDescendant({ disabled })
  const open =
    index !== -1
      ? isArray(selectedIndex)
        ? selectedIndex.includes(index)
        : selectedIndex === index
      : false

  if (open && disabled)
    console.warn(`Accordion: Cannot open a disabled accordion item`)

  const onChange = useCallback(
    (open: boolean) => {
      if (index === -1) return

      if (multiple && isArray(selectedIndex)) {
        setIndex(
          open
            ? selectedIndex.concat(index)
            : selectedIndex.filter((i) => i !== index),
        )
      } else if (open) {
        setIndex(index)
      } else if (toggle) {
        setIndex(-1)
      }
    },
    [multiple, toggle, index, selectedIndex, setIndex],
  )

  const onFocus = useCallback(() => {
    setFocusedIndex(index)
  }, [setFocusedIndex, index])

  const onClick = useCallback(() => {
    onChange(!open)
    setFocusedIndex(index)
  }, [index, setFocusedIndex, open, onChange])

  const onKeyDown = useCallback(
    (ev: KeyboardEvent<HTMLButtonElement>) => {
      runKeyAction(ev, {
        ArrowDown: () => {
          const next = descendants.enabledNextValue(index)

          next?.node.focus()
        },
        ArrowUp: () => {
          const prev = descendants.enabledPrevValue(index)

          prev?.node.focus()
        },
        End: () => {
          const last = descendants.enabledLastValue()

          last?.node.focus()
        },
        Home: () => {
          const first = descendants.enabledFirstValue()

          first?.node.focus()
        },
      })
    },
    [descendants, index],
  )

  const getItemProps: PropGetter = useCallback(
    (props = {}) =>
      mergeProps({ "data-expanded": dataAttr(open) }, rest, props)(),
    [open, rest],
  )

  const getButtonProps: PropGetter<"button"> = useCallback(
    ({ ref, ...props } = {}) => ({
      id: itemId,
      type: "button",
      "aria-controls": panelId,
      "aria-disabled": ariaAttr((!multiple && !toggle && open) || disabled),
      "aria-expanded": open,
      ...props,
      ref: mergeRefs(register, ref),
      disabled,
      onClick: handlerAll(props.onClick, onClick),
      onFocus: handlerAll(props.onFocus, onFocus),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [
      itemId,
      open,
      panelId,
      multiple,
      toggle,
      disabled,
      register,
      onClick,
      onFocus,
      onKeyDown,
    ],
  )

  const getPanelProps: PropGetter = useCallback(
    ({ "aria-labelledby": ariaLabelledby, ...props } = {}) => ({
      id: panelId,
      "aria-labelledby": cx(ariaLabelledby, itemId),
      role: "region",
      ...props,
    }),
    [itemId, panelId],
  )

  const getIconProps: PropGetter<"svg"> = useCallback(
    (props) => ({
      "aria-disabled": ariaAttr((!multiple && !toggle && open) || disabled),
      "aria-expanded": open,
      "aria-hidden": true,
      role: "presentation",
      ...props,
    }),
    [multiple, toggle, open, disabled],
  )

  return {
    disabled,
    open,
    getButtonProps,
    getIconProps,
    getItemProps,
    getPanelProps,
  }
}

export type UseAccordionItemReturn = ReturnType<typeof useAccordionItem>
